34 5678</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class="wp-block-column"><!-- wp:paragraph {"align":"right","style":{"typography":{"fontSize":"25px"}}} -->\n<p class="has-text-align-right" style="font-size:25px">INSTAGRAM · <a href="#">BILLETS</a></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:spacer {"height":50} -->\n<div style="height:50px" aria-hidden="true" class="wp-block-spacer"></div>\n<!-- /wp:spacer --></div>\n<!-- /wp:group -->";}i:5;O:8:"stdClass":7:{s:2:"id";i:1372;s:5:"title";O:8:"stdClass":1:{s:8:"rendered";s:39:"Image sur couleur unie avec description";}s:7:"content";O:8:"stdClass":2:{s:8:"rendered";s:2051:"\n<div class="wp-block-columns alignfull is-layout-flex wp-container-core-columns-is-layout-0e47273b wp-block-columns-is-layout-flex">\n<div class="wp-block-column is-layout-flow wp-block-column-is-layout-flow" style="flex-basis:50%">\n<div class="wp-block-cover has-background-dim" style="background-color:#f6f6f6;min-height:600px;aspect-ratio:unset;"><div class="wp-block-cover__inner-container is-layout-flow wp-block-cover-is-layout-flow">\n<div class="wp-block-image"><figure class="aligncenter size-medium"><img loading="lazy" decoding="async" width="263" height="300" src="https://s.w.org/patterns/files/2021/06/wire-sculpture-263x300.jpg" alt="" class="wp-image-571" srcset="https://s.w.org/patterns/files/2021/06/wire-sculpture-263x300.jpg 263w, https://s.w.org/patterns/files/2021/06/wire-sculpture-898x1024.jpg 898w, https://s.w.org/patterns/files/2021/06/wire-sculpture-768x875.jpg 768w, https://s.w.org/patterns/files/2021/06/wire-sculpture-1347x1536.jpg 1347w, https://s.w.org/patterns/files/2021/06/wire-sculpture.jpg 1658w" sizes="auto, (max-width: 263px) 100vw, 263px" /></figure></div>\n</div></div>\n</div>\n\n\n\n<div class="wp-block-column is-vertically-aligned-center is-layout-flow wp-block-column-is-layout-flow" style="padding-top:1em;padding-right:1em;padding-bottom:1em;padding-left:1em">\n<div class="wp-block-columns is-layout-flex wp-container-core-columns-is-layout-0e47273b wp-block-columns-is-layout-flex">\n<div class="wp-block-column is-layout-flow wp-block-column-is-layout-flow" style="flex-basis:320px">\n<p class="has-small-font-size wp-block-paragraph" style="line-height:1.6"><strong>Avion</strong></p>\n\n\n\n<p class="has-small-font-size wp-block-paragraph" style="line-height:1.6">Fil de cuivre, base en bois. J’ai créé cette pièce à la fin de l’année 2008. Pour cette œuvre, j’ai cherché à transmettre à la fois la lourdeur industrielle d’un avion, mais aussi la sensation de flottement, semblable à celui d’un nuage, que l’on ressent lorsque l’on est dans un avion.</p>\n</div>\n</div>\n</div>\n</div>\n";s:9:"protected";b:0;}s:4:"meta";O:8:"stdClass":10:{s:14:"_crdt_document";s:0:"";s:31:"jetpack_post_was_ever_published";b:0;s:13:"wpop_keywords";s:0:"";s:16:"wpop_description";s:43:"Image avec aplat de couleur et description.";s:19:"wpop_viewport_width";i:1200;s:16:"wpop_block_types";a:1:{i:0;s:0:"";}s:11:"wpop_locale";s:5:"fr_FR";s:15:"wpop_wp_version";s:0:"";s:25:"wpop_contains_block_types";s:61:"core/column,core/columns,core/cover,core/image,core/paragraph";s:9:"footnotes";s:0:"";}s:14:"category_slugs";a:2:{i:0;s:6:"images";i:1;s:4:"text";}s:13:"keyword_slugs";a:1:{i:0;s:8:"featured";}s:15:"pattern_content";s:1925:"<!-- wp:columns {"align":"full"} -->\n<div class="wp-block-columns alignfull"><!-- wp:column {"width":"50%"} -->\n<div class="wp-block-column" style="flex-basis:50%"><!-- wp:cover {"customOverlayColor":"#f6f6f6","minHeight":600} -->\n<div class="wp-block-cover has-background-dim" style="background-color:#f6f6f6;min-height:600px"><div class="wp-block-cover__inner-container"><!-- wp:image {"align":"center","id":571,"sizeSlug":"medium","linkDestination":"none"} -->\n<div class="wp-block-image"><figure class="aligncenter size-medium"><img src="https://s.w.org/patterns/files/2021/06/wire-sculpture-263x300.jpg" alt="" class="wp-image-571" /></figure></div>\n<!-- /wp:image --></div></div>\n<!-- /wp:cover --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {"verticalAlignment":"center","style":{"spacing":{"padding":{"top":"1em","right":"1em","bottom":"1em","left":"1em"}}}} -->\n<div class="wp-block-column is-vertically-aligned-center" style="padding-top:1em;padding-right:1em;padding-bottom:1em;padding-left:1em"><!-- wp:columns -->\n<div class="wp-block-columns"><!-- wp:column {"width":"320px"} -->\n<div class="wp-block-column" style="flex-basis:320px"><!-- wp:paragraph {"style":{"typography":{"lineHeight":"1.6"}},"fontSize":"small"} -->\n<p class="has-small-font-size" style="line-height:1.6"><strong>Avion</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {"style":{"typography":{"lineHeight":"1.6"}},"fontSize":"small"} -->\n<p class="has-small-font-size" style="line-height:1.6">Fil de cuivre, base en bois. J’ai créé cette pièce à la fin de l’année 2008. Pour cette œuvre, j’ai cherché à transmettre à la fois la lourdeur industrielle d’un avion, mais aussi la sensation de flottement, semblable à celui d’un nuage, que l’on ressent lorsque l’on est dans un avion.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->";}i:6;O:8:"stdClass":7:{s:2:"id";i:8085;s:5:"title";O:8:"stdClass":1:{s:8:"rendered";s:36:"Images décalées avec descriptions.";}s:7:"content";O:8:"stdClass":2:{s:8:"rendered";s:1946:"\n<div class="wp-block-columns is-layout-flex wp-container-core-columns-is-layout-0e47273b wp-block-columns-is-layout-flex">\n<div class="wp-block-column is-layout-flow wp-block-column-is-layout-flow">\n<figure class="wp-block-image size-large"><img loading="lazy" decoding="async" width="793" height="1024" src="https://s.w.org/patterns/files/2021/06/Iris-793x1024.jpg" alt="" class="wp-image-525" srcset="https://s.w.org/patterns/files/2021/06/Iris-793x1024.jpg 793w, https://s.w.org/patterns/fi