:"33.38%"} -->\n<div class="wp-block-column" style="flex-basis:33.38%"><!-- wp:paragraph {"style":{"color":{"text":"#000000"},"typography":{"fontSize":"17px"}}} -->\n<p class="has-text-color" style="color:#000000;font-size:17px"><em>Nature</em>, in the common sense, refers to essences unchanged by man; space, the air, the river, the leaf.&nbsp;<em>Art</em>&nbsp;is applied to the mixture of his will with the same things, as in a house, a canal, a statue, a picture. </p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {"style":{"color":{"text":"#000000"},"typography":{"fontSize":"17px"}}} -->\n<p class="has-text-color" style="color:#000000;font-size:17px">But his operations taken together are so insignificant, a little chipping, baking, patching, and washing, that in an impression so grand as that of the world on the human mind, they do not vary the result.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {"width":"33%"} -->\n<div class="wp-block-column" style="flex-basis:33%"><!-- wp:spacer {"height":"2vw"} -->\n<div style="height:2vw" aria-hidden="true" class="wp-block-spacer"></div>\n<!-- /wp:spacer -->\n\n<!-- wp:image {"sizeSlug":"large","linkDestination":"none"} -->\n<figure class="wp-block-image size-large"><img src="https://s.w.org/images/core/5.8/outside-01.jpg" alt="Le soleil se couchant derrière une forêt dense." /></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {"width":"33.62%"} -->\n<div class="wp-block-column" style="flex-basis:33.62%"><!-- wp:image {"sizeSlug":"large","linkDestination":"none"} -->\n<figure class="wp-block-image size-large"><img src="https://s.w.org/images/core/5.8/outside-02.jpg" alt="Des éoliennes se tiennent sur une plaine herbeuse, avec un ciel bleu en arrière-plan." /></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:columns {"align":"wide","style":{"spacing":{"blockGap":{"left":"3vw"}}}} -->\n<div class="wp-block-columns alignwide"><!-- wp:column {"width":"69%"} -->\n<div class="wp-block-column" style="flex-basis:69%"><!-- wp:image {"sizeSlug":"large","linkDestination":"none"} -->\n<figure class="wp-block-image size-large"><img src="https://s.w.org/images/core/5.8/outside-03.jpg" alt="Le soleil brille au dessus d’une crête donnant sur le bord de mer. Plus loin, une voiture est visible." /></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {"verticalAlignment":"center","width":"33%"} -->\n<div class="wp-block-column is-vertically-aligned-center" style="flex-basis:33%"><!-- wp:spacer {"height":"2vw"} -->\n<div style="height:2vw" aria-hidden="true" class="wp-block-spacer"></div>\n<!-- /wp:spacer -->\n\n<!-- wp:paragraph {"style":{"color":{"text":"#000000"},"typography":{"fontSize":"17px"}}} -->\n<p class="has-text-color" style="color:#000000;font-size:17px">Sans doute n’avons-nous pas de questions à poser qui soient sans réponse. Nous devons faire confiance à la perfection de la création au point de croire que, quelle que soit la curiosité que l’ordre des choses a éveillée dans notre esprit, l’ordre des choses peut la satisfaire. La condition de chaque homme est une solution en hiéroglyphes aux questions qu’il poserait.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->";}i:11;O:8:"stdClass":7:{s:2:"id";i:1355;s:5:"title";O:8:"stdClass":1:{s:8:"rendered";s:40:"Média et texte avec image sur la gauche";}s:7:"content";O:8:"stdClass":2:{s:8:"rendered";s:644:"\n<div class="wp-block-media-text alignfull is-stacked-on-mobile is-vertically-aligned-center"><figure class="wp-block-media-text__media"><img decoding="async" src="https://s.w.org/images/core/5.8/architecture-04.jpg" alt="Vue de près d’un détail architectural." /></figure><div class="wp-block-media-text__content">\n<h3 class="wp-block-heading has-text-align-center has-text-color" style="color:#000000"><strong>Espaces ouverts</strong></h3>\n\n\n\