k-cover__background has-background-dim-60 has-background-dim"></span><img decoding="async" class="wp-block-cover__image-background" alt="" src="https://s.w.org/images/core/5.8/forest.jpg" data-object-fit="cover" /><div class="wp-block-cover__inner-container is-layout-flow wp-block-cover-is-layout-flow">\n<h2 class="wp-block-heading alignwide has-text-color" style="color:#ffe074;font-size:64px">Forêt.</h2>\n\n\n\n<div class="wp-block-columns alignwide is-layout-flex wp-container-core-columns-is-layout-0e47273b wp-block-columns-is-layout-flex">\n<div class="wp-block-column is-layout-flow wp-block-column-is-layout-flow" style="flex-basis:55%">\n<div style="height:330px" aria-hidden="true" class="wp-block-spacer"></div>\n\n\n\n<p class="has-text-color wp-block-paragraph" style="color:#ffe074;font-size:12px;line-height:1.3"><em>Même un enfant sait combien la forêt est précieuse. L’odeur fraîche des arbres, à vous couper le souffle. L’écho des oiseaux volant au-dessus de cette magnitude dense. Un climat stable, une vie durable et diversifiée et une source de culture. Pourtant, les forêts et d’autres écosystèmes sont en péril, menacés de devenir des terres de culture, des pâturages ou des plantations.</em></p>\n</div>\n\n\n\n<div class="wp-block-column is-layout-flow wp-block-column-is-layout-flow"></div>\n</div>\n</div></div>\n";s:9:"protected";b:0;}s:4:"meta";O:8:"stdClass":10:{s:14:"_crdt_document";s:0:"";s:31:"jetpack_post_was_ever_published";b:0;s:13:"wpop_keywords";s:0:"";s:16:"wpop_description";s:35:"Bannière avec une citation en haut";s:19:"wpop_viewport_width";i:1200;s:16:"wpop_block_types";a:1:{i:0;s:0:"";}s:11:"wpop_locale";s:5:"fr_FR";s:15:"wpop_wp_version";s:0:"";s:25:"wpop_contains_block_types";s:75:"core/column,core/columns,core/cover,core/heading,core/paragraph,core/spacer";s:9:"footnotes";s:0:"";}s:14:"category_slugs";a:1:{i:0;s:6:"banner";}s:13:"keyword_slugs";a:2:{i:0;s:4:"core";i:1;s:8:"featured";}s:15:"pattern_content";s:1777:"<!-- wp:cover {"url":"https://s.w.org/images/core/5.8/forest.jpg","dimRatio":60,"minHeight":800,"align":"full"} -->\n<div class="wp-block-cover alignfull" style="min-height:800px"><span aria-hidden="true" class="wp-block-cover__background has-background-dim-60 has-background-dim"></span><img class="wp-block-cover__image-background" alt="" src="https://s.w.org/images/core/5.8/forest.jpg" data-object-fit="cover" /><div class="wp-block-cover__inner-container"><!-- wp:heading {"align":"wide","style":{"color":{"text":"#ffe074"},"typography":{"fontSize":"64px"}}} -->\n<h2 class="wp-block-heading alignwide has-text-color" style="color:#ffe074;font-size:64px">Forêt.</h2>\n<!-- /wp:heading -->\n\n<!-- wp:columns {"align":"wide"} -->\n<div class="wp-block-columns alignwide"><!-- wp:column {"width":"55%"} -->\n<div class="wp-block-column" style="flex-basis:55%"><!-- wp:spacer {"height":"330px"} -->\n<div style="height:330px" aria-hidden="true" class="wp-block-spacer"></div>\n<!-- /wp:spacer -->\n\n<!-- wp:paragraph {"style":{"color":{"text":"#ffe074"},"typography":{"lineHeight":"1.3","fontSize":"12px"}}} -->\n<p class="has-text-color" style="color:#ffe074;font-size:12px;line-height:1.3"><em>Même un enfant sait combien la forêt est précieuse. L’odeur fraîche des arbres, à vous couper le souffle. L’écho des oiseaux volant au-dessus de cette magnitude dense. Un climat stable, une vie durable et diversifiée et une source de culture. Pourtant, les forêts et d’autres écosystèmes sont en péril, menacés de devenir des terres de culture, des pâturages ou des plantations.</em></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class="wp-block-column"></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div></div>\n<!-- /wp:cover -->";}i:13;O:8:"stdClass":7:{s:2:"id";i:1326;s:5:"title";O:8:"stdClass":1:{s:8:"rendered";s:5:"titre";}s:7:"content";O:8:"stdClass":2:{s:8:"rendered";s:608:"\n<h2 class="alignwide wp-block-heading" id="we-re-a-studio-in-berlin-with-an-international-pr