INSERT INTO `wp_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES
	(1, 1, '2026-03-26 08:57:02', '2026-03-26 07:57:02', '<!-- wp:paragraph -->\n<p>Bienvenue sur WordPress. Ceci est votre premier article. Modifiez-le ou supprimez-le, puis commencez à écrire !</p>\n<!-- /wp:paragraph -->', 'Bonjour tout le monde !', '', 'trash', 'open', 'open', '', 'bonjour-tout-le-monde__trashed', '', '', '2026-03-26 09:52:06', '2026-03-26 08:52:06', '', 0, 'http://localhost:8080/?p=1', 0, 'post', '', 1);
INSERT INTO `wp_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES
	(2, 1, '2026-03-26 08:57:02', '2026-03-26 07:57:02', '<!-- wp:paragraph -->\n<p>Ceci est une page d’exemple. C’est différent d’un article de blog parce qu’elle restera au même endroit et apparaîtra dans la navigation de votre site (dans la plupart des thèmes). La plupart des gens commencent par une page « À propos » qui les présente aux personnes visitant le site. Cela pourrait ressembler à quelque chose comme cela :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:quote -->\n<blockquote class="wp-block-quote">\n<!-- wp:paragraph -->\n<p>Bonjour ! Je suis un mécanicien qui aspire à devenir acteur, et voici mon site. J’habite à Bordeaux, j’ai un super chien baptisé Russell, et j’aime la vodka (ainsi qu’être surpris par la pluie soudaine lors de longues balades sur la plage au coucher du soleil).</p>\n<!-- /wp:paragraph -->\n</blockquote>\n<!-- /wp:quote -->\n\n<!-- wp:paragraph -->\n<p>…ou quelque chose comme cela :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:quote -->\n<blockquote class="wp-block-quote">\n<!-- wp:paragraph -->\n<p>La société 123 Machin Truc a été créée en 1971, et n’a cessé de proposer au public des machins-trucs de qualité depuis lors. Située à Saint-Remy-en-Bouzemont-Saint-Genest-et-Isson, 123 Machin Truc emploie 2 000 personnes, et fabrique toutes sortes de bidules supers pour la communauté bouzemontoise.</p>\n<!-- /wp:paragraph -->\n</blockquote>\n<!-- /wp:quote -->\n\n<!-- wp:paragraph -->\n<p>En tant que nouvel utilisateur ou utilisatrice de WordPress, vous devriez vous rendre sur <a href="http://localhost:8080/wp-admin/">votre tableau de bord</a> pour supprimer cette page et créer de nouvelles pages pour votre contenu. Amusez-vous bien !</p>\n<!-- /wp:paragraph -->', 'Page d’exemple', '', 'publish', 'closed', 'open', '', 'page-d-exemple', '', '', '2026-03-26 08:57:02', '2026-03-26 07:57:02', '', 0, 'http://localhost:8080/?page_id=2', 0, 'page', '', 0),
	(3, 1, '2026-03-26 08:57:02', '2026-03-26 07:57:02', '<!-- wp:heading -->\n<h2 class="wp-block-heading">Qui sommes-nous ?</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class="privacy-policy-tutorial">Texte suggéré : </strong>L’adresse de notre site est : http://localhost:8080.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class="wp-block-heading">Commentaires</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class="privacy-policy-tutorial">Texte suggéré : </strong>Quand vous laissez un commentaire sur notre site, les données inscrites dans le formulaire de commentaire, ainsi que votre adresse IP et l’agent utilisateur de votre navigateur sont collectés pour nous aider à la détection des commentaires indésirables.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>Une chaîne anonymisée créée à partir de votre adresse e-mail (également appelée hash) peut être envoyée au service Gravatar pour vérifier si vous utilisez ce dernier. Les clauses de confidentialité du service Gravatar sont disponibles ici : https://automattic.com/privacy/. Après validation de votre commentaire, votre photo de profil sera visible publiquement à coté de votre commentaire.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class="wp-block-heading">Médias</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class="privacy-policy-tutorial">Texte suggéré : </strong>Si vous téléversez des images sur le site, nous vous conseillons d’éviter de téléverser des images contenant des données EXIF de coordonnées GPS. Les personnes visitant votre site peuvent télécharger et extraire des données de localisation depuis ces images.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class="wp-block-heading">Cookies</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class="privacy-policy-tutorial">Texte suggéré : </strong>Si vous déposez un commentaire sur notre site, il vous sera proposé d’enregistrer votre nom, adresse e-mail et site dans des cookies. C’est uniquement pour votre confort afin de ne pas avoir à saisir ces informations si vous déposez un autre commentaire plus tard. Ces cookies expirent au bout d’un an.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>Si vous vous rendez sur la page de connexion, un cookie temporaire sera créé afin de déterminer si votre navigateur accepte les cookies. Il ne contient pas de données personnelles et sera supprimé automatiquement à la fermeture de votre navigateur.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>Lorsque vous vous connecterez, nous mettrons en place un certain nombre de cookies pour enregistrer vos informations de connexion et vos préférences d’écran. La durée de vie d’un cookie de connexion est de deux jours, celle d’un cookie d’option d’écran est d’un an. Si vous cochez « Se souvenir de moi », votre cookie de connexion sera conservé pendant deux semaines. Si vous vous déconnectez de votre compte, le cookie de connexion sera effacé.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>En modifiant ou en publiant une publication, un cookie supplémentaire sera enregistré dans votre navigateur. Ce cookie ne comprend aucune donnée personnelle. Il indique simplement l’ID de la publication que vous venez de modifier. Il expire au bout d’un jour.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class="wp-block-heading">Contenu embarqué depuis d’autres sites</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class="privacy-policy-tutorial">Texte suggéré : </strong>Les articles de ce site peuvent inclure des contenus intégrés (par exemple des vidéos, images, articles…). Le contenu intégré depuis d’autres sites se comporte de la même manière que si le visiteur se rendait sur cet autre site.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>Ces sites web pourraient collecter des données sur vous, utiliser des cookies, embarquer des outils de suivis tiers, suivre vos interactions avec ces contenus embarqués si vous disposez d’un compte connecté sur leur site web.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class="wp-block-heading">Utilisation et transmission de vos données personnelles</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class="privacy-policy-tutorial">Texte suggéré : </strong>Si vous demandez une réinitialisation de votre mot de passe, votre adresse IP sera incluse dans l’e-mail de réinitialisation.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class="wp-block-heading">Durées de stockage de vos données</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class="privacy-policy-tutorial">Texte suggéré : </strong>Si vous laissez un commentaire, le commentaire et ses métadonnées sont conservés indéfiniment. Cela permet de reconnaître et approuver automatiquement les commentaires suivants au lieu de les laisser dans la file de modération.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>Pour les comptes qui s’inscrivent sur notre site (le cas échéant), nous stockons également les données personnelles indiquées dans leur profil. Tous les comptes peuvent voir, modifier ou supprimer leurs informations personnelles à tout moment (à l’exception de leur identifiant). Les gestionnaires du site peuvent aussi voir et modifier ces informations.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class="wp-block-heading">Les droits que vous avez sur vos données</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class="privacy-policy-tutorial">Texte suggéré : </strong>Si vous avez un compte ou si vous avez laissé des commentaires sur le site, vous pouvez demander à recevoir un fichier contenant toutes les données personnelles que nous possédons à votre sujet, incluant celles que vous nous avez fournies. Vous pouvez également demander la suppression des données personnelles vous concernant. Cela ne prend pas en compte les données stockées à des fins administratives, légales ou pour des raisons de sécurité.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class="wp-block-heading">Où vos données sont envoyées</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class="privacy-policy-tutorial">Texte suggéré : </strong>Les commentaires des visiteurs peuvent être vérifiés à l’aide d’un service automatisé de détection des commentaires indésirables.</p>\n<!-- /wp:paragraph -->\n', 'Politique de confidentialité', '', 'draft', 'closed', 'open', '', 'politique-de-confidentialite', '', '', '2026-03-26 08:57:02', '2026-03-26 07:57:02', '', 0, 'http://localhost:8080/?page_id=3', 0, 'page', '', 0),
	(4, 1, '2026-03-26 08:57:35', '0000-00-00 00:00:00', '', 'Brouillon auto', '', 'auto-draft', 'open', 'open', '', '', '', '', '2026-03-26 08:57:35', '0000-00-00 00:00:00', '', 0, 'http://localhost:8080/?p=4', 0, 'post', '', 0),
	(5, 1, '2026-03-26 09:27:36', '0000-00-00 00:00:00', '', 'Accueil', '', 'draft', 'closed', 'closed', '', '', '', '', '2026-03-26 09:27:36', '0000-00-00 00:00:00', '', 0, 'http://localhost:8080/?p=5', 1, 'nav_menu_item', '', 0),
	(6, 1, '2026-03-26 09:27:36', '0000-00-00 00:00:00', ' ', '', '', 'draft', 'closed', 'closed', '', '', '', '', '2026-03-26 09:27:36', '0000-00-00 00:00:00', '', 0, 'http://localhost:8080/?p=6', 1, 'nav_menu_item', '', 0),
	(7, 1, '2026-03-26 09:31:08', '2026-03-26 08:31:08', '<!-- wp:heading {"level":3} -->\n<h3 class="wp-block-heading">Installation de Wordpress avec Docker:</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {"ordered":true} -->\n<ol class="wp-block-list"><!-- wp:list-item -->\n<li>Créer un dossier pour le projet</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Créer un fichier docker-compose.yaml dans ce dossier, avec un container web et un container pour la base de donnée.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Dans le terminal, naviguer jusqu\'au dossier du projet et lancer la commande docker compose up</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Une fois l\'installation terminé, ouvrir un navigateur et se rendre sur <a href="http://localhost:8080">http://localhost:xxxx</a> (xxxx = numéro du port d\'écoute du container web )</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Suivez les instructions de l\'installation Wordpress.</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {"level":3} -->\n<h3 class="wp-block-heading">Création d\'un thème de base Wordpress:</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {"ordered":true} -->\n<ol class="wp-block-list"><!-- wp:list-item -->\n<li>Se rendre dans le dossier de thèmes (votre-dossier-wordpress/<code>wp-content/themes/</code></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Créer un dossier pour votre thème</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Créer un ficher index.php et un fichier style.css , ces fichiers sont obligatoire pour activer votre thème</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Activer votre thème dans le menu apparence -> Themes de Wordpress</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {"align":"right"} -->\n<p class="has-text-align-right"><a href="https://github.com/Moutonmalpoli/ecf-wordpress-20260318-TC">Code source du thème</a></p>\n<!-- /wp:paragraph -->', 'A Propos', '', 'publish', 'closed', 'closed', '', 'a-propos', '', '', '2026-03-26 10:11:31', '2026-03-26 09:11:31', '', 0, 'http://localhost:8080/?page_id=7', 0, 'page', '', 0),
	(8, 1, '2026-03-26 09:31:08', '2026-03-26 08:31:08', '', 'A Propos', '', 'inherit', 'closed', 'closed', '', '7-revision-v1', '', '', '2026-03-26 09:31:08', '2026-03-26 08:31:08', '', 7, 'http://localhost:8080/?p=8', 0, 'revision', '', 0),
	(10, 1, '2026-03-26 11:44:30', '2026-03-26 08:31:34', ' ', '', '', 'publish', 'closed', 'closed', '', '10', '', '', '2026-03-26 11:44:30', '2026-03-26 10:44:30', '', 0, 'http://localhost:8080/?p=10', 5, 'nav_menu_item', '', 0),
	(12, 1, '2026-03-26 09:50:52', '2026-03-26 08:50:52', '<!-- wp:paragraph -->\n<p>L\'héritage architectural de l\'urbanisme du XIXe siècle acquiert une dimension mystique lorsque la foule disparaît et qu\'il ne reste que la pierre.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {"level":3} -->\n<h3 class="wp-block-heading">La symétrie des ombres</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href="https://github.com/Moutonmalpoli/ecf-wordpress-20260318-TC/blob/main/assets/article-paris.md#la-symétrie-des-ombres"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Sous la lumière rasante, les façades s\'alignent avec une rigueur militaire. Les balcons filants du deuxième et du cinquième étage tracent des lignes de fuite infinies, soulignant la perspective forcée des boulevards. Sans le mouvement des passants, l\'œil s’arrête enfin sur la modénature : la finesse des consoles, le grain du calcaire lutécien et la répétition hypnotique des hautes fenêtres.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {"level":3} -->\n<h3 class="wp-block-heading">Un théâtre sans acteurs</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href="https://github.com/Moutonmalpoli/ecf-wordpress-20260318-TC/blob/main/assets/article-paris.md#un-théâtre-sans-acteurs"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Le silence transforme la rue en une scène de théâtre vide. Les larges trottoirs, conçus pour la déambulation bourgeoise et la circulation fluide, révèlent leur véritable échelle. Ce n\'est plus un lieu de passage, mais un volume monumental où le vide semble peser autant que le plein. Les toits en ardoise, avec leur inclinaison caractéristique à 45 degrés, découpent sur le ciel une silhouette bleutée qui semble veiller sur la solitude du pavé.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>« Dans ce dépouillement, l\'immeuble haussmannien cesse d\'être une simple habitation pour redevenir une sculpture urbaine. »</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {"level":3} -->\n<h3 class="wp-block-heading">La respiration du calcaire</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href="https://github.com/Moutonmalpoli/ecf-wordpress-20260318-TC/blob/main/assets/article-paris.md#la-respiration-du-calcaire"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>L\'absence de bruit permet de percevoir la texture de la ville. On remarque alors comment la pierre boit la lumière ou rejette l\'ombre selon l\'heure. Ce "silence des boulevards" n\'est pas une absence, mais une présence : celle d\'une vision urbanistique qui a cherché à discipliner le chaos pour imposer l\'ordre de la ligne droite.</p>\n<!-- /wp:paragraph -->', 'L\'architecture Haussmann: Le silence des boulevards', '', 'publish', 'open', 'open', '', 'larchitecture-haussmann-le-silence-des-boulevards', '', '', '2026-03-26 13:44:29', '2026-03-26 12:44:29', '', 0, 'http://localhost:8080/?p=12', 0, 'post', '', 0),
	(13, 1, '2026-03-26 09:49:54', '2026-03-26 08:49:54', '', 'paris', '', 'inherit', 'open', 'closed', '', 'paris', '', '', '2026-03-26 09:49:54', '2026-03-26 08:49:54', '', 12, 'http://localhost:8080/wp-content/uploads/2026/03/paris.png', 0, 'attachment', 'image/png', 0),
	(14, 1, '2026-03-26 09:50:52', '2026-03-26 08:50:52', '<!-- wp:image {"id":13,"sizeSlug":"full","linkDestination":"custom"} -->\n<figure class="wp-block-image size-full"><img src="http://localhost:8080/wp-content/uploads/2026/03/paris.png" alt="" class="wp-image-13"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p>L\'héritage architectural de l\'urbanisme du XIXe siècle acquiert une dimension mystique lorsque la foule disparaît et qu\'il ne reste que la pierre.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {"level":3} -->\n<h3 class="wp-block-heading">La symétrie des ombres</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href="https://github.com/Moutonmalpoli/ecf-wordpress-20260318-TC/blob/main/assets/article-paris.md#la-symétrie-des-ombres"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Sous la lumière rasante, les façades s\'alignent avec une rigueur militaire. Les balcons filants du deuxième et du cinquième étage tracent des lignes de fuite infinies, soulignant la perspective forcée des boulevards. Sans le mouvement des passants, l\'œil s’arrête enfin sur la modénature : la finesse des consoles, le grain du calcaire lutécien et la répétition hypnotique des hautes fenêtres.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {"level":3} -->\n<h3 class="wp-block-heading">Un théâtre sans acteurs</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href="https://github.com/Moutonmalpoli/ecf-wordpress-20260318-TC/blob/main/assets/article-paris.md#un-théâtre-sans-acteurs"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Le silence transforme la rue en une scène de théâtre vide. Les larges trottoirs, conçus pour la déambulation bourgeoise et la circulation fluide, révèlent leur véritable échelle. Ce n\'est plus un lieu de passage, mais un volume monumental où le vide semble peser autant que le plein. Les toits en ardoise, avec leur inclinaison caractéristique à 45 degrés, découpent sur le ciel une silhouette bleutée qui semble veiller sur la solitude du pavé.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>« Dans ce dépouillement, l\'immeuble haussmannien cesse d\'être une simple habitation pour redevenir une sculpture urbaine. »</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {"level":3} -->\n<h3 class="wp-block-heading">La respiration du calcaire</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href="https://github.com/Moutonmalpoli/ecf-wordpress-20260318-TC/blob/main/assets/article-paris.md#la-respiration-du-calcaire"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>L\'absence de bruit permet de percevoir la texture de la ville. On remarque alors comment la pierre boit la lumière ou rejette l\'ombre selon l\'heure. Ce "silence des boulevards" n\'est pas une absence, mais une présence : celle d\'une vision urbanistique qui a cherché à discipliner le chaos pour imposer l\'ordre de la ligne droite.</p>\n<!-- /wp:paragraph -->', 'L\'architecture Haussmann: Le silence des boulevards', '', 'inherit', 'closed', 'closed', '', '12-revision-v1', '', '', '2026-03-26 09:50:52', '2026-03-26 08:50:52', '', 12, 'http://localhost:8080/?p=14', 0, 'revision', '', 0),
	(15, 1, '2026-03-26 09:51:53', '2026-03-26 08:51:53', '<!-- wp:paragraph -->\n<p><a href="https://github.com/Moutonmalpoli/ecf-wordpress-20260318-TC/blob/main/assets/article-lille.md#feu-flamand--la-chaleur-des-nuits-boréales"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>À la découverte de l\'esthétique des briques rouges et de la scène culturelle vibrante qui définissent l\'identité transfrontalière unique de Lille.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {"level":3} -->\n<h3 class="wp-block-heading">Le dialogue des textures</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href="https://github.com/Moutonmalpoli/ecf-wordpress-20260318-TC/blob/main/assets/article-lille.md#le-dialogue-des-textures"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Lille ne se contente pas d’exposer sa brique ; elle la met en scène. Ce matériau humble, né de la terre des Flandres, capture la lumière rasante pour transformer chaque façade en un brasier immobile. Dans le Vieux-Lille, le contraste entre le rouge flamboyant du calcaire de Lezennes et le blanc des chambranles crée une rythmique visuelle presque musicale. C’est une architecture qui refuse la froideur, préférant la rugosité chaleureuse au lissé impersonnel de la modernité.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {"level":3} -->\n<h3 class="wp-block-heading">L\'effervescence des estaminets</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href="https://github.com/Moutonmalpoli/ecf-wordpress-20260318-TC/blob/main/assets/article-lille.md#leffervescence-des-estaminets"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Lorsque le ciel s\'assombrit, la chaleur migre vers l\'intérieur. Les fenêtres s\'illuminent, révélant la vie qui palpite derrière les carreaux. La scène culturelle ne s\'arrête pas aux musées ; elle s\'invite aux tables de bois brut. Dans ces refuges de convivialité, l\'identité transfrontalière s\'exprime par le goût : l\'amertume du houblon rencontre la rondeur du fromage de caractère, tandis que les rires effacent les frontières géographiques.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>« Ici, le Nord n\'est pas une direction, c\'est un tempérament : une résistance joyeuse à la mélancolie des nuits d\'hiver. »</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {"level":3} -->\n<h3 class="wp-block-heading">Une modernité héritée</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href="https://github.com/Moutonmalpoli/ecf-wordpress-20260318-TC/blob/main/assets/article-lille.md#une-modernité-héritée"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Lille ne reste pas figée dans son passé textile. L\'ancienne brique industrielle, autrefois symbole de labeur, est devenue le canevas d\'une création contemporaine audacieuse. Des friches transformées en centres d\'art aux quartiers futuristes, la ville prouve que son feu intérieur est loin de s\'éteindre. Elle se réinvente sans jamais trahir sa couleur originelle, celle d\'une terre qui sait rester ardente sous la grisaille.</p>\n<!-- /wp:paragraph -->', 'Feu flamand : La chaleur des nuits boréales', '', 'publish', 'open', 'open', '', 'feu-flamand-la-chaleur-des-nuits-boreales', '', '', '2026-03-26 13:44:19', '2026-03-26 12:44:19', '', 0, 'http://localhost:8080/?p=15', 0, 'post', '', 0),
	(16, 1, '2026-03-26 09:51:41', '2026-03-26 08:51:41', '', 'lille', '', 'inherit', 'open', 'closed', '', 'lille', '', '', '2026-03-26 09:51:41', '2026-03-26 08:51:41', '', 15, 'http://localhost:8080/wp-content/uploads/2026/03/lille.png', 0, 'attachment', 'image/png', 0),
	(17, 1, '2026-03-26 09:51:53', '2026-03-26 08:51:53', '<!-- wp:paragraph -->\n<p><a href="https://github.com/Moutonmalpoli/ecf-wordpress-20260318-TC/blob/main/assets/article-lille.md#feu-flamand--la-chaleur-des-nuits-boréales"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:image {"id":16,"sizeSlug":"full","linkDestination":"custom"} -->\n<figure class="wp-block-image size-full"><img src="http://localhost:8080/wp-content/uploads/2026/03/lille.png" alt="" class="wp-image-16"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p>À la découverte de l\'esthétique des briques rouges et de la scène culturelle vibrante qui définissent l\'identité transfrontalière unique de Lille.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {"level":3} -->\n<h3 class="wp-block-heading">Le dialogue des textures</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href="https://github.com/Moutonmalpoli/ecf-wordpress-20260318-TC/blob/main/assets/article-lille.md#le-dialogue-des-textures"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Lille ne se contente pas d’exposer sa brique ; elle la met en scène. Ce matériau humble, né de la terre des Flandres, capture la lumière rasante pour transformer chaque façade en un brasier immobile. Dans le Vieux-Lille, le contraste entre le rouge flamboyant du calcaire de Lezennes et le blanc des chambranles crée une rythmique visuelle presque musicale. C’est une architecture qui refuse la froideur, préférant la rugosité chaleureuse au lissé impersonnel de la modernité.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {"level":3} -->\n<h3 class="wp-block-heading">L\'effervescence des estaminets</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href="https://github.com/Moutonmalpoli/ecf-wordpress-20260318-TC/blob/main/assets/article-lille.md#leffervescence-des-estaminets"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Lorsque le ciel s\'assombrit, la chaleur migre vers l\'intérieur. Les fenêtres s\'illuminent, révélant la vie qui palpite derrière les carreaux. La scène culturelle ne s\'arrête pas aux musées ; elle s\'invite aux tables de bois brut. Dans ces refuges de convivialité, l\'identité transfrontalière s\'exprime par le goût : l\'amertume du houblon rencontre la rondeur du fromage de caractère, tandis que les rires effacent les frontières géographiques.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>« Ici, le Nord n\'est pas une direction, c\'est un tempérament : une résistance joyeuse à la mélancolie des nuits d\'hiver. »</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {"level":3} -->\n<h3 class="wp-block-heading">Une modernité héritée</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href="https://github.com/Moutonmalpoli/ecf-wordpress-20260318-TC/blob/main/assets/article-lille.md#une-modernité-héritée"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Lille ne reste pas figée dans son passé textile. L\'ancienne brique industrielle, autrefois symbole de labeur, est devenue le canevas d\'une création contemporaine audacieuse. Des friches transformées en centres d\'art aux quartiers futuristes, la ville prouve que son feu intérieur est loin de s\'éteindre. Elle se réinvente sans jamais trahir sa couleur originelle, celle d\'une terre qui sait rester ardente sous la grisaille.</p>\n<!-- /wp:paragraph -->', 'Feu flamand : La chaleur des nuits boréales', '', 'inherit', 'closed', 'closed', '', '15-revision-v1', '', '', '2026-03-26 09:51:53', '2026-03-26 08:51:53', '', 15, 'http://localhost:8080/?p=17', 0, 'revision', '', 0),
	(18, 1, '2026-03-26 09:52:06', '2026-03-26 08:52:06', '<!-- wp:paragraph -->\n<p>Bienvenue sur WordPress. Ceci est votre premier article. Modifiez-le ou supprimez-le, puis commencez à écrire !</p>\n<!-- /wp:paragraph -->', 'Bonjour tout le monde !', '', 'inherit', 'closed', 'closed', '', '1-revision-v1', '', '', '2026-03-26 09:52:06', '2026-03-26 08:52:06', '', 1, 'http://localhost:8080/?p=18', 0, 'revision', '', 0),
	(19, 1, '2026-03-26 09:54:27', '2026-03-26 08:54:27', 'Picsum ID: 403', 'Picsum ID: 403', '', 'inherit', 'open', 'closed', '', 'picsum-id-403', '', '', '2026-03-26 09:54:27', '2026-03-26 08:54:27', '', 0, 'http://localhost:8080/wp-content/uploads/2026/03/4dd9f172-4c7e-3930-a81f-e044e7455f2d.jpg', 0, 'attachment', 'image/jpeg', 0),
