	(38, 1, '2026-03-26 10:10:59', '2026-03-26 09:10:59', '<!-- wp:heading {"level":3} -->\n<h3 class="wp-block-heading">Installation de Wordpress avec Docker:</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {"ordered":true} -->\n<ol class="wp-block-list"><!-- wp:list-item -->\n<li>Créer un dossier pour le projet</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Créer un fichier docker-compose.yaml dans ce dossier, avec un container web et un container pour la base de donnée.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Dans le terminal, naviguer jusqu\'au dossier du projet et lancer la commande docker compose up</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Une fois l\'installation terminé, ouvrir un navigateur et se rendre sur <a href="http://localhost:8080">http://localhost:xxxx</a> (xxxx = numéro du port d\'écoute du container web )</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Suivez les instructions de l\'installation Wordpress.</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {"level":3} -->\n<h3 class="wp-block-heading">Création d\'un theme de base Wordpress:</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {"ordered":true} -->\n<ol class="wp-block-list"><!-- wp:list-item -->\n<li>Se rendre dans le dossier de themes (votre-dossier-wordpress/<code>wp-content/themes/</code></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Créer un dossier pour votre theme</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Créer un ficher index.php et un fichier style.css , ces fichiers sont obligatoire pour activer votre theme</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Activer votre theme dans le menu apparence -> Themes de Wordpress</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><a href="https://github.com/Moutonmalpoli/ecf-wordpress-20260318-TC">Code source du thème</a></p>\n<!-- /wp:paragraph -->', 'A Propos', '', 'inherit', 'closed', 'closed', '', '7-autosave-v1', '', '', '2026-03-26 10:10:59', '2026-03-26 09:10:59', '', 7, 'http://localhost:8080/?p=38', 0, 'revision', '', 0),
	(39, 1, '2026-03-26 10:11:07', '2026-03-26 09:11:07', '<!-- wp:heading {"level":3} -->\n<h3 class="wp-block-heading">Installation de Wordpress avec Docker:</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {"ordered":true} -->\n<ol class="wp-block-list"><!-- wp:list-item -->\n<li>Créer un dossier pour le projet</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Créer un fichier docker-compose.yaml dans ce dossier, avec un container web et un container pour la base de donnée.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Dans le terminal, naviguer jusqu\'au dossier du projet et lancer la commande docker compose up</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Une fois l\'installation terminé, ouvrir un navigateur et se rendre sur <a href="http://localhost:8080">http://localhost:xxxx</a> (xxxx = numéro du port d\'écoute du container web )</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Suivez les instructions de l\'installation Wordpress.</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {"level":3} -->\n<h3 class="wp-block-heading">Création d\'un theme de base Wordpress:</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {"ordered":true} -->\n<ol class="wp-block-list"><!-- wp:list-item -->\n<li>Se rendre dans le dossier de themes (votre-dossier-wordpress/<code>wp-content/themes/</code></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Créer un dossier pour votre theme</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Créer un ficher index.php et un fichier style.css , ces fichiers sont obligatoire pour activer votre theme</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Activer votre theme dans le menu apparence -> Themes de Wordpress</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {"align":"right"} -->\n<p class="has-text-align-right"><a href="https://github.com/Moutonmalpoli/ecf-wordpress-20260318-TC">Code source du thème</a></p>\n<!-- /wp:paragraph -->', 'A Propos', '', 'inherit', 'closed', 'closed', '', '7-revision-v1', '', '', '2026-03-26 10:11:07', '2026-03-26 09:11:07', '', 7, 'http://localhost:8080/?p=39', 0, 'revision', '', 0),
	(40, 1, '2026-03-26 10:11:31', '2026-03-26 09:11:31', '<!-- wp:heading {"level":3} -->\n<h3 class="wp-block-heading">Installation de Wordpress avec Docker:</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {"ordered":true} -->\n<ol class="wp-block-list"><!-- wp:list-item -->\n<li>Créer un dossier pour le projet</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Créer un fichier docker-compose.yaml dans ce dossier, avec un container web et un container pour la base de donnée.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Dans le terminal, naviguer jusqu\'au dossier du projet et lancer la commande docker compose up</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Une fois l\'installation terminé, ouvrir un navigateur et se rendre sur <a href="http://localhost:8080">http://localhost:xxxx</a> (xxxx = numéro du port d\'écoute du container web )</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Suivez les instructions de l\'installation Wordpress.</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {"level":3} -->\n<h3 class="wp-block-heading">Création d\'un thème de base Wordpress:</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {"ordered":true} -->\n<ol class="wp-block-list"><!-- wp:list-item -->\n<li>Se rendre dans le dossier de thèmes (votre-dossier-wordpress/<code>wp-content/themes/</code></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Créer un dossier pour votre thème</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Créer un ficher index.php et un fichier style.css , ces fichiers sont obligatoire pour activer votre thème</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Activer votre thème dans le menu apparence -> Themes de Wordpress</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {"align":"right"} -->\n<p class="has-text-align-right"><a href="htt